fn visual_vessel(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  // interior gradient: deep amber-dark at the base, cool near the throat
  var col = mix(vec3f(0.030, 0.020, 0.014), vec3f(0.010, 0.012, 0.022), (uv.y + 1.0) * 0.5);
  col = mix(col, vec3f(0.05, 0.032, 0.016), pow(max(0.0, -uv.y - 0.45), 1.6) * 0.9);
  // curved glass walls — a soft rim of caught light, breathing very slowly
  let wall = smoothstep(0.99, 0.90, max(abs(uv.x), abs(uv.y)));
  col += vec3f(0.10, 0.12, 0.14) * (1.0 - wall) * (0.55 + 0.10 * sin(t * 0.23 + uv.y * 2.0));
  // the cursor is a lens-light moving through the glass
  let mp = vec2f(uni(0), uni(1));
  let md = uv - mp;
  col += vec3f(0.055, 0.045, 0.030) * exp(-dot(md, md) * 9.0);
  // idle motes drifting in the fluid
  for (var i = 0; i < 3; i++) {
    let fi = f32(i);
    let mpos = vec2f(sin(t * 0.05 + fi * 2.1) * 0.7, sin(t * 0.037 + fi * 4.4) * 0.7);
    col += vec3f(0.05, 0.05, 0.045) * exp(-dot(uv - mpos, uv - mpos) * 500.0);
  }
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(1.0)), 1.0);
}

fn visual_ember(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  var p = uv;
  p.x += 0.10 * sin(t * 2.1 + uv.y * 3.0) * (0.4 - uv.y * 0.5);
  let lick = 0.72 + 0.12 * sin(t * 1.7);
  let body = smoothstep(lick, 0.05, length(vec2f(p.x * 1.5, (p.y + 0.15) * (1.0 + max(0.0, -p.y) * 0.7))));
  let core = exp(-dot(p, p) * 6.0);
  var col = mix(vec3f(0.85, 0.22, 0.02), vec3f(1.0, 0.75, 0.25), core);
  let a = clamp(body * 0.9 + core * 0.4, 0.0, 1.0) * smoothstep(1.0, 0.85, length(uv));
  if (a < 0.01) { return vec4f(0.0); }
  return vec4f(col * (1.1 + 0.25 * core), a);
}

fn visual_dew(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let wob = vec2f(uv.x * (1.0 + 0.06 * sin(time * 2.3)), uv.y * (1.0 - 0.06 * sin(time * 2.3)));
  let r = length(wob);
  if (r > 1.0) { return vec4f(0.0); }
  let body = smoothstep(0.85, 0.7, r);
  let hi = exp(-dot(wob - vec2f(-0.3, -0.35), wob - vec2f(-0.3, -0.35)) * 18.0);
  let col = mix(vec3f(0.10, 0.32, 0.55), vec3f(0.65, 0.9, 1.0), hi) + vec3f(0.08, 0.18, 0.3) * smoothstep(0.9, 0.4, r);
  return vec4f(col, body * 0.92);
}

fn visual_gale(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let r = length(uv);
  if (r > 1.0) { return vec4f(0.0); }
  let ang = atan2(uv.y, uv.x);
  let sw = sin(ang * 3.0 - r * 7.0 + time * 2.4);
  let arm = smoothstep(0.2, 0.9, sw) * smoothstep(1.0, 0.25, r);
  let col = vec3f(0.75, 0.85, 0.9);
  return vec4f(col, arm * 0.30 + exp(-r * r * 4.0) * 0.08);
}

fn visual_loam(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let bump = 0.12 * sin(atan2(uv.y, uv.x) * 5.0 + 1.3) + 0.08 * sin(atan2(uv.y, uv.x) * 9.0);
  let r = length(uv) + bump;
  if (r > 0.95) { return vec4f(0.0); }
  let body = smoothstep(0.95, 0.8, r);
  let speck = smoothstep(0.75, 1.0, sin(uv.x * 21.0) * sin(uv.y * 19.0));
  let col = mix(vec3f(0.16, 0.10, 0.05), vec3f(0.34, 0.24, 0.12), speck + 0.3 * (1.0 - r));
  return vec4f(col, body);
}

fn visual_mist(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let r = length(uv);
  if (r > 1.0) { return vec4f(0.0); }
  let puff = exp(-r * r * 2.2) * (0.75 + 0.15 * sin(time * 0.9 + uv.x * 3.0));
  return vec4f(vec3f(0.78, 0.84, 0.9), puff * 0.4);
}

fn visual_rain(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = vec2f(uv.x * 2.4, uv.y);
  let d = length(vec2f(p.x, p.y - clamp(p.y, -0.6, 0.6)));
  let a = smoothstep(0.5, 0.1, d) * 0.85;
  if (a < 0.01) { return vec4f(0.0); }
  return vec4f(mix(vec3f(0.25, 0.45, 0.7), vec3f(0.6, 0.85, 1.0), -uv.y * 0.5 + 0.5), a);
}

fn visual_magma(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let r = length(uv) + 0.1 * sin(atan2(uv.y, uv.x) * 4.0);
  if (r > 0.95) { return vec4f(0.0); }
  let crack = smoothstep(0.55, 0.95, sin(uv.x * 12.0 + sin(uv.y * 9.0) * 2.0));
  let glow = 0.7 + 0.3 * sin(time * 0.8);
  let col = mix(vec3f(0.06, 0.04, 0.04), vec3f(1.0, 0.35, 0.05) * glow, crack);
  return vec4f(col, smoothstep(0.95, 0.8, r));
}

fn visual_moss(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let fuzz = 0.14 * sin(atan2(uv.y, uv.x) * 11.0 + time * 0.4);
  let r = length(uv) + fuzz;
  if (r > 0.95) { return vec4f(0.0); }
  let spore = smoothstep(0.8, 1.0, sin(uv.x * 25.0 + time * 0.5) * sin(uv.y * 23.0));
  let col = mix(vec3f(0.05, 0.16, 0.06), vec3f(0.35, 0.65, 0.25), spore + 0.25 * (1.0 - r));
  return vec4f(col, smoothstep(0.95, 0.75, r));
}

fn visual_wildfire(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let ang = atan2(uv.y, uv.x);
  let tongue = pow(max(0.0, sin(ang * 4.0 + time * 2.6)), 3.0) * 0.4;
  let r = length(uv) - tongue;
  if (r > 0.9) { return vec4f(0.0); }
  let heat = smoothstep(0.9, 0.1, r) * (0.85 + 0.15 * sin(time * 2.3 + ang * 2.0));
  let col = mix(vec3f(1.0, 0.3, 0.02), vec3f(1.0, 0.9, 0.4), exp(-dot(uv, uv) * 5.0));
  return vec4f(col * 1.4, heat);
}

fn visual_storm(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let r = length(uv);
  if (r > 1.0) { return vec4f(0.0); }
  let ang = atan2(uv.y, uv.x);
  let knot = 0.5 + 0.5 * sin(ang * 2.0 - r * 5.0 + time * 1.5);
  var col = mix(vec3f(0.07, 0.07, 0.12), vec3f(0.25, 0.24, 0.38), knot);
  // an arc of caught lightning, wandering gently (params.x pulses on thunder)
  let arc = smoothstep(0.06, 0.0, abs(uv.y - 0.3 * sin(uv.x * 4.0 + time * 1.1))) * smoothstep(1.0, 0.4, r);
  col += vec3f(0.7, 0.75, 1.0) * arc * (0.25 + 0.75 * clamp(params.x, 0.0, 1.0));
  return vec4f(col, smoothstep(1.0, 0.6, r) * 0.92);
}

fn visual_ash(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let r = length(uv) + 0.1 * sin(atan2(uv.y, uv.x) * 6.0 + 2.0);
  if (r > 0.9) { return vec4f(0.0); }
  let col = vec3f(0.32, 0.31, 0.30) * (0.7 + 0.3 * (1.0 - r));
  return vec4f(col, smoothstep(0.9, 0.6, r) * 0.8);
}

fn visual_star(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let r = length(uv);
  if (r > 1.0) { return vec4f(0.0); }
  let ang = atan2(uv.y, uv.x);
  let ray = pow(max(0.0, cos(ang * 5.0 + time * 0.5)), 8.0);
  let core = exp(-r * r * 14.0);
  let col = vec3f(1.0, 0.92, 0.6) * (core * 2.2 + ray * smoothstep(1.0, 0.2, r) * 0.8);
  return vec4f(col, clamp(core * 1.5 + ray * 0.5, 0.0, 1.0) * smoothstep(1.0, 0.75, r));
}

fn visual_glassgem(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let qa = vec2f(abs(uv.x), abs(uv.y));
  let hex = max(qa.x * 0.866 + qa.y * 0.5, qa.y);
  if (hex > 0.85) { return vec4f(0.0); }
  let facet = 0.5 + 0.5 * sin(uv.x * 7.0 + uv.y * 5.0 + 1.0);
  let edge = smoothstep(0.85, 0.78, hex) - smoothstep(0.7, 0.5, hex);
  var col = vec3f(0.55, 0.7, 0.72) * (0.25 + 0.3 * facet);
  col += vec3f(0.5 + 0.5 * sin(time * 0.4), 0.5 + 0.5 * sin(time * 0.4 + 2.1), 0.5 + 0.5 * sin(time * 0.4 + 4.2)) * edge * 0.5;
  return vec4f(col, smoothstep(0.85, 0.75, hex) * 0.75 + edge * 0.3);
}

fn visual_flare(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let age = clamp(params.x, 0.0, 1.0);
  if (age >= 1.0) { return vec4f(0.0); }
  let r = length(uv);
  let ring = smoothstep(0.12, 0.0, abs(r - age * 0.95));
  let bloom = exp(-r * r * 8.0) * (1.0 - age);
  let col = vec3f(params.y, params.z, params.w);
  let a = clamp(ring * (1.0 - age) + bloom, 0.0, 1.0);
  if (a < 0.01) { return vec4f(0.0); }
  return vec4f(col * (1.2 + bloom), a);
}
